#include <stdio.h>
#include <stdint.h>

// IPv4 Header Structure (20 bytes without options)
typedef struct {
    uint8_t  version_ihl;    // Version (4 bits) + IHL (4 bits)
    uint8_t  tos;            // Type of Service
    uint16_t total_length;  // Total packet length
    uint16_t identification; // Identification for fragmentation
    uint8_t  flags_fragment; // Flags (3 bits) + Fragment Offset (13 bits)
    uint8_t  ttl;            // Time to Live
    uint8_t  protocol;       // Protocol (TCP=6, UDP=17, ICMP=1)
    uint16_t checksum;       // Header Checksum
    uint32_t src_ip;         // Source IP Address
    uint32_t dst_ip;         // Destination IP Address
    // Options follow if IHL > 5
} IPv4Header;

void parse_ipv4_header(unsigned char *buffer) {
    IPv4Header *ip = (IPv4Header *)buffer;

    uint8_t version = (ip->version_ihl >> 4) & 0x0F;
    uint8_t ihl = ip->version_ihl & 0x0F;
    uint8_t header_len = ihl * 4;

    printf("Version: %d\n", version);
    printf("Header Length: %d bytes\n", header_len);
    printf("TTL: %d\n", ip->ttl);
    printf("Protocol: %d\n", ip->protocol);
}

// Note: IP addresses stored in network byte order (big-endian)
// Need ntohl() to convert to host byte order for display
